import React, { useState, useEffect } from 'react'
import { supabase } from '../../lib/supabaseClient'

const PAYMENT_METHODS = [
  'JazzCash',
  'EasyPaisa', 
  'Bank Transfer',
  'Cash on Delivery',
  'Rocket',
  'UPaisa'
]

export const Marketplace: React.FC = () => {
  const [listings, setListings] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [currentUser, setCurrentUser] = useState<any>(null)
  const [userProfile, setUserProfile] = useState<any>(null)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [buyingId, setBuyingId] = useState<string | null>(null)
  const [selectedListing, setSelectedListing] = useState<any>(null)
  const [showDetail, setShowDetail] = useState(false)
  const [error, setError] = useState('')

  const [formData, setFormData] = useState({
    item_name: '',
    description: '',
    price: '',
    condition: 'Good',
    category: '',
    seller_phone: '',
    payment_methods: ['JazzCash', 'EasyPaisa'] as string[]
  })

  useEffect(() => {
    loadUserAndListings()
  }, [])

  const loadUserAndListings = async () => {
    setLoading(true)
    setError('')

    const { data: { user } } = await supabase.auth.getUser()
    setCurrentUser(user)

    if (user) {
      const { data: profile, error: profileError } = await supabase
        .from('users')
        .select('*')
        .eq('id', user.id)
        .single()

      if (profileError) {
        const { error: insertError } = await supabase
          .from('users')
          .insert({
            id: user.id,
            full_name: user.user_metadata?.full_name || user.email?.split('@')[0] || 'User',
            email: user.email,
            role: 'Player',
            status: 'active'
          })

        if (!insertError) {
          const { data: newProfile } = await supabase
            .from('users')
            .select('*')
            .eq('id', user.id)
            .single()
          setUserProfile(newProfile)
        }
      } else {
        setUserProfile(profile)
      }
    }

    // Load ONLY AVAILABLE listings
    const { data, error: listingsError } = await supabase
      .from('marketplace')
      .select('*')
      .eq('status', 'AVAILABLE')
      .order('created_at', { ascending: false })

    if (!listingsError) {
      setListings(data || [])
    }

    setLoading(false)
  }

  const handleCreateListing = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')

    if (!currentUser || !userProfile) {
      setError('⚠️ Please login first')
      return
    }

    const price = parseFloat(formData.price)
    if (isNaN(price) || price <= 0) {
      setError('⚠️ Please enter a valid price')
      return
    }

    if (!formData.item_name.trim()) {
      setError('⚠️ Please enter an item name')
      return
    }

    if (!formData.seller_phone.trim()) {
      setError('⚠️ Please enter your phone number for payment')
      return
    }

    const { error: insertError } = await supabase
      .from('marketplace')
      .insert({
        seller_id: userProfile.id,
        item_name: formData.item_name.trim(),
        description: formData.description.trim(),
        price: price,
        condition: formData.condition,
        category: formData.category.trim() || 'Other',
        seller_phone: formData.seller_phone.trim(),
        payment_methods: formData.payment_methods,
        status: 'AVAILABLE'
      })

    if (insertError) {
      setError('❌ Failed to create listing: ' + insertError.message)
    } else {
      alert('✅ Listing created successfully!')
      setShowCreateForm(false)
      setFormData({
        item_name: '',
        description: '',
        price: '',
        condition: 'Good',
        category: '',
        seller_phone: '',
        payment_methods: ['JazzCash', 'EasyPaisa']
      })
      loadUserAndListings()
    }
  }

  const handleBuy = async (listing: any) => {
    if (!currentUser || !userProfile) {
      alert('⚠️ Please login first')
      return
    }

    if (listing.seller_id === userProfile.id) {
      alert('⚠️ You cannot buy your own item')
      return
    }

    if (listing.status !== 'AVAILABLE') {
      alert('⚠️ This item is no longer available')
      return
    }

    setBuyingId(listing.id)

    // Show payment confirmation with seller details
    const paymentMethods = listing.payment_methods || ['JazzCash', 'EasyPaisa']
    const phoneNumber = listing.seller_phone || 'Not provided'

    const confirmMessage = `
Buy "${listing.item_name}" for $${listing.price}?

📱 Seller Contact: ${phoneNumber}
💳 Payment Methods: ${paymentMethods.join(', ')}

Contact the seller to arrange payment.
Click OK to confirm purchase.
    `

    if (!window.confirm(confirmMessage)) {
      setBuyingId(null)
      return
    }

    // Update listing status to SOLD
    const { error: updateError } = await supabase
      .from('marketplace')
      .update({ status: 'SOLD' })
      .eq('id', listing.id)

    if (updateError) {
      alert('❌ Purchase failed: ' + updateError.message)
      setBuyingId(null)
      return
    }

    // Record the purchase
    await supabase
      .from('purchases')
      .insert({
        listing_id: listing.id,
        buyer_id: userProfile.id
      })

    alert(`✅ Purchase confirmed for "${listing.item_name}"!\n\n📱 Contact seller: ${phoneNumber}\n💳 Pay via: ${paymentMethods.join(', ')}`)

    setBuyingId(null)
    loadUserAndListings() // This will refresh and remove the sold item
  }

  const openDetail = (listing: any) => {
    setSelectedListing(listing)
    setShowDetail(true)
  }

  const closeDetail = () => {
    setShowDetail(false)
    setSelectedListing(null)
  }

  const togglePaymentMethod = (method: string) => {
    setFormData(prev => {
      const methods = prev.payment_methods.includes(method)
        ? prev.payment_methods.filter(m => m !== method)
        : [...prev.payment_methods, method]
      return { ...prev, payment_methods: methods }
    })
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: '#0a0a0a',
      color: 'white',
      padding: '24px'
    }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h1 style={{ color: '#FFD700', fontSize: '28px' }}>🛒 Marketplace</h1>
            <p style={{ color: '#666' }}>Buy & sell sports equipment</p>
          </div>
          <button
            onClick={() => setShowCreateForm(!showCreateForm)}
            style={{
              padding: '10px 20px',
              background: showCreateForm ? '#ff4444' : '#c8a200',
              color: showCreateForm ? 'white' : '#0a0a0a',
              border: 'none',
              borderRadius: '8px',
              fontWeight: 'bold',
              cursor: 'pointer'
            }}
          >
            {showCreateForm ? '✕ Cancel' : '+ Sell Item'}
          </button>
        </div>

        {error && (
          <div style={{
            background: '#ff444433',
            color: '#ff4444',
            padding: '12px',
            borderRadius: '8px',
            marginBottom: '16px'
          }}>
            ⚠️ {error}
          </div>
        )}

        {/* Create Listing Form */}
        {showCreateForm && (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '12px',
            padding: '24px',
            marginBottom: '24px'
          }}>
            <h3 style={{ color: '#FFD700', marginBottom: '16px' }}>📝 Create Listing</h3>
            <form onSubmit={handleCreateListing}>
              <div style={{ marginBottom: '12px' }}>
                <input
                  type="text"
                  value={formData.item_name}
                  onChange={(e) => setFormData({ ...formData, item_name: e.target.value })}
                  placeholder="Item name *"
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                  required
                />
              </div>
              <div style={{ marginBottom: '12px' }}>
                <textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Description"
                  rows={2}
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px',
                    fontFamily: 'inherit'
                  }}
                />
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '12px' }}>
                <input
                  type="number"
                  value={formData.price}
                  onChange={(e) => setFormData({ ...formData, price: e.target.value })}
                  placeholder="Price ($) *"
                  step="0.01"
                  min="0.01"
                  style={{
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                  required
                />
                <select
                  value={formData.condition}
                  onChange={(e) => setFormData({ ...formData, condition: e.target.value })}
                  style={{
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                >
                  <option value="New">🆕 New</option>
                  <option value="Like New">✨ Like New</option>
                  <option value="Good">👍 Good</option>
                  <option value="Fair">👌 Fair</option>
                  <option value="Poor">🔧 Poor</option>
                </select>
              </div>
              <div style={{ marginBottom: '12px' }}>
                <input
                  type="text"
                  value={formData.category}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                  placeholder="Category (e.g. Football, Cricket, Tennis...)"
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                />
              </div>

              {/* Seller Phone - Required for payments */}
              <div style={{ marginBottom: '12px' }}>
                <input
                  type="tel"
                  value={formData.seller_phone}
                  onChange={(e) => setFormData({ ...formData, seller_phone: e.target.value })}
                  placeholder="📱 Phone Number for Payment *"
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                  required
                />
                <div style={{ color: '#555', fontSize: '11px', marginTop: '4px' }}>
                  Buyers will see this to arrange payment (JazzCash, EasyPaisa, etc.)
                </div>
              </div>

              {/* Payment Methods - Multi-select */}
              <div style={{ marginBottom: '16px' }}>
                <label style={{ color: '#aaa', fontSize: '13px', display: 'block', marginBottom: '8px' }}>
                  💳 Accepted Payment Methods
                </label>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {PAYMENT_METHODS.map(method => (
                    <label
                      key={method}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '6px',
                        padding: '6px 14px',
                        background: formData.payment_methods.includes(method) 
                          ? 'rgba(200,162,0,0.2)' 
                          : '#1a1a1a',
                        border: `1px solid ${formData.payment_methods.includes(method) ? '#c8a200' : '#333'}`,
                        borderRadius: '20px',
                        cursor: 'pointer',
                        fontSize: '13px',
                        color: formData.payment_methods.includes(method) ? '#FFD700' : '#888'
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={formData.payment_methods.includes(method)}
                        onChange={() => togglePaymentMethod(method)}
                        style={{ display: 'none' }}
                      />
                      {method}
                    </label>
                  ))}
                </div>
              </div>

              <button
                type="submit"
                style={{
                  width: '100%',
                  padding: '12px',
                  background: 'linear-gradient(to right, #c8a200, #FFD700)',
                  border: 'none',
                  borderRadius: '8px',
                  color: '#0a0a0a',
                  fontWeight: 'bold',
                  cursor: 'pointer',
                  fontSize: '15px'
                }}
              >
                🚀 Post Listing
              </button>
            </form>
          </div>
        )}

        {/* Listings - Only shows AVAILABLE items */}
        {loading ? (
          <div style={{ textAlign: 'center', color: '#666', padding: '40px' }}>Loading...</div>
        ) : listings.length === 0 ? (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '12px',
            padding: '40px',
            textAlign: 'center',
            color: '#666'
          }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>🛒</div>
            <h3 style={{ color: '#888' }}>No listings available</h3>
            <p>Be the first to sell something!</p>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '16px' }}>
            {listings.map((item) => {
              const isOwner = item.seller_id === userProfile?.id
              const isBuying = buyingId === item.id

              return (
                <div 
                  key={item.id} 
                  style={{
                    background: '#0d0d0d',
                    border: '1px solid #c8a20020',
                    borderRadius: '12px',
                    padding: '16px',
                    transition: 'all 0.3s',
                    cursor: 'pointer'
                  }}
                  onClick={() => openDetail(item)}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.borderColor = '#c8a200'
                    e.currentTarget.style.transform = 'scale(1.02)'
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.borderColor = '#c8a20020'
                    e.currentTarget.style.transform = 'scale(1)'
                  }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <h3 style={{ fontSize: '16px', fontWeight: 'bold' }}>{item.item_name}</h3>
                    <span style={{
                      background: '#1a3a1a',
                      color: '#52c07a',
                      padding: '2px 10px',
                      borderRadius: '12px',
                      fontSize: '10px',
                      fontWeight: 'bold',
                      whiteSpace: 'nowrap'
                    }}>
                      {item.condition}
                    </span>
                  </div>
                  {item.category && (
                    <p style={{ color: '#666', fontSize: '12px', marginTop: '4px' }}>📁 {item.category}</p>
                  )}
                  {item.description && (
                    <p style={{ color: '#888', fontSize: '13px', margin: '8px 0' }}>
                      {item.description.length > 60 ? item.description.substring(0, 60) + '...' : item.description}
                    </p>
                  )}

                  {/* Payment methods badge */}
                  {item.payment_methods && item.payment_methods.length > 0 && (
                    <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', marginBottom: '8px' }}>
                      {item.payment_methods.slice(0, 3).map((method: string) => (
                        <span key={method} style={{
                          background: '#1a1a1a',
                          color: '#888',
                          padding: '2px 8px',
                          borderRadius: '12px',
                          fontSize: '9px'
                        }}>
                          {method}
                        </span>
                      ))}
                      {item.payment_methods.length > 3 && (
                        <span style={{
                          background: '#1a1a1a',
                          color: '#666',
                          padding: '2px 8px',
                          borderRadius: '12px',
                          fontSize: '9px'
                        }}>
                          +{item.payment_methods.length - 3} more
                        </span>
                      )}
                    </div>
                  )}

                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '12px' }}>
                    <span style={{ color: '#FFD700', fontSize: '20px', fontWeight: 'bold' }}>
                      ${Number(item.price).toFixed(2)}
                    </span>
                    <button
                      onClick={(e) => {
                        e.stopPropagation()
                        handleBuy(item)
                      }}
                      disabled={isOwner || isBuying}
                      style={{
                        padding: '6px 16px',
                        background: isOwner ? '#333' : isBuying ? '#666' : '#c8a200',
                        color: isOwner ? '#666' : isBuying ? '#444' : '#0a0a0a',
                        border: 'none',
                        borderRadius: '8px',
                        fontWeight: 'bold',
                        cursor: isOwner ? 'not-allowed' : 'pointer',
                        fontSize: '13px',
                        minWidth: '80px'
                      }}
                    >
                      {isOwner ? 'Your Item' : isBuying ? '⏳' : 'Buy Now'}
                    </button>
                  </div>
                </div>
              )
            })}
          </div>
        )}
      </div>

      {/* Item Detail Modal */}
      {showDetail && selectedListing && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(0,0,0,0.85)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000,
          padding: '20px'
        }}>
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20040',
            borderRadius: '16px',
            padding: '32px',
            maxWidth: '500px',
            width: '100%',
            maxHeight: '90vh',
            overflow: 'auto'
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
              <h2 style={{ color: '#FFD700', fontSize: '24px' }}>{selectedListing.item_name}</h2>
              <button
                onClick={closeDetail}
                style={{
                  background: 'transparent',
                  border: 'none',
                  color: '#666',
                  fontSize: '24px',
                  cursor: 'pointer'
                }}
              >
                ✕
              </button>
            </div>

            <div style={{ display: 'flex', gap: '8px', marginBottom: '12px', flexWrap: 'wrap' }}>
              <span style={{
                background: '#1a3a1a',
                color: '#52c07a',
                padding: '2px 12px',
                borderRadius: '20px',
                fontSize: '12px'
              }}>
                {selectedListing.condition}
              </span>
              {selectedListing.category && (
                <span style={{
                  background: '#1a1a3a',
                  color: '#7fc8f8',
                  padding: '2px 12px',
                  borderRadius: '20px',
                  fontSize: '12px'
                }}>
                  📁 {selectedListing.category}
                </span>
              )}
              <span style={{
                background: '#1a3a1a',
                color: '#52c07a',
                padding: '2px 12px',
                borderRadius: '20px',
                fontSize: '12px'
              }}>
                {selectedListing.status}
              </span>
            </div>

            {selectedListing.description && (
              <p style={{ color: '#aaa', fontSize: '14px', marginBottom: '16px', lineHeight: '1.6' }}>
                {selectedListing.description}
              </p>
            )}

            {/* Seller & Payment Info */}
            <div style={{
              background: '#1a1a1a',
              borderRadius: '10px',
              padding: '16px',
              marginBottom: '16px'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                <span style={{ fontSize: '18px' }}>📱</span>
                <span style={{ color: '#aaa' }}>Seller Contact:</span>
                <span style={{ color: '#FFD700', fontWeight: 'bold' }}>
                  {selectedListing.seller_phone || 'Not provided'}
                </span>
              </div>
              <div style={{ display: 'flex', alignItems: 'flex-start', gap: '8px' }}>
                <span style={{ fontSize: '18px' }}>💳</span>
                <div>
                  <span style={{ color: '#aaa' }}>Payment Methods:</span>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px', marginTop: '4px' }}>
                    {(selectedListing.payment_methods || ['JazzCash', 'EasyPaisa']).map((method: string) => (
                      <span key={method} style={{
                        background: '#0d0d0d',
                        color: '#888',
                        padding: '2px 10px',
                        borderRadius: '12px',
                        fontSize: '11px',
                        border: '1px solid #333'
                      }}>
                        {method}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            <div style={{
              borderTop: '1px solid #1a1a1a',
              paddingTop: '16px'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <span style={{ color: '#666', fontSize: '13px' }}>Price</span>
                  <div style={{ color: '#FFD700', fontSize: '28px', fontWeight: 'bold' }}>
                    ${Number(selectedListing.price).toFixed(2)}
                  </div>
                </div>
                <button
                  onClick={() => {
                    closeDetail()
                    handleBuy(selectedListing)
                  }}
                  disabled={selectedListing.seller_id === userProfile?.id}
                  style={{
                    padding: '12px 32px',
                    background: selectedListing.seller_id === userProfile?.id ? '#333' : '#c8a200',
                    color: selectedListing.seller_id === userProfile?.id ? '#666' : '#0a0a0a',
                    border: 'none',
                    borderRadius: '10px',
                    fontWeight: 'bold',
                    fontSize: '16px',
                    cursor: selectedListing.seller_id === userProfile?.id ? 'not-allowed' : 'pointer'
                  }}
                >
                  {selectedListing.seller_id === userProfile?.id ? 'Your Item' : 'Buy Now'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
